INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p01','2026-04-01',1,'teaser','✨','Reveal — Edizione 1','Primo annuncio ufficiale. Nome, data, luogo. Richiamare l''Ed.0 con "Si torna". Tono evocativo.','Si torna. Sabato 25 aprile. Marsam Locanda, Bene Vagienna. COINCIDENZE — raffinate casualita'', occhi attenti. Edizione 1. #COINCIDENZE2026','Post Instagram quadrato','da_fare','[]','Grafica con brand kit. Nessuna spiegazione, solo atmosfera. Considerare di togliere i pin dall''Ed.0.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p02','2026-04-03',1,'teaser','👁','La tagline','Post tipografico sulla tagline. Solo la frase, nessun contesto. Come nell''Ed.0 ma con visual aggiornato.','raffinate casualita'', occhi attenti. #COINCIDENZE2026 #RaffinateCasualita','Post Instagram quadrato','da_fare','[]','Minimal. Playfair Display. Lasciare che parli da sola.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p03','2026-04-05',1,'teaser','📍','Il luogo — Marsam Locanda','Presentazione del luogo. Foto della locanda, del giardino, dell''atmosfera. Tono caldo.','Un posto dove il tempo rallenta. Marsam Locanda, Bene Vagienna. Ci troviamo qui il 25 aprile. #COINCIDENZE2026 #MarsamLocanda #BeneVagienna','Post o Reel breve (venue tour)','da_fare','["Marco Marsam"]','Foto/video della location. Collab con @marsamlocanda. Reel 15-30sec consigliato per reach.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p04','2026-04-07',2,'artisti','📷','Spotlight — Fotografia','5 fotografi, una mostra collettiva. Carosello con una slide per fotografo + slide location.','Cinque sguardi. Una mostra. Luca Fumero · Mauro Curti · Owen Zaccagnino · Paolo Sicca · Tazio Secchiaroli. Mostra fotografica 10:00-20:00 · Galleria. #COINCIDENZE2026 #Fotografia','Carosello (6 slide)','da_fare','["Luca Fumero","Mauro Curti","Owen Zaccagnino","Paolo Sicca","Tazio Secchiaroli"]','Una slide per fotografo con foto e nome. Collab post con @iamluchino e @maurocurti_.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p05','2026-04-09',2,'artisti','🗿','Spotlight — Scultura e Pittura','4 artisti tra giardino e sala. Materia che prende forma.','La materia prende forma. Sculture nel giardino, pittura in sala. Crux · Franco S. Alessandria · Cristina Saimandi · Marco Fiaschi. 10:00-20:00. #COINCIDENZE2026 #Scultura #Arte','Carosello (5 slide)','da_fare','["Crux","Franco Sebastiano Alessandria","Cristina Saimandi","Marco Fiaschi"]','Collab con @crux2019 e @cristinasaimandiartist. Usare foto opere.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p06','2026-04-11',2,'artisti','🎸','Spotlight — Ancreus Live','Trio acustico. Due set live nella Sala Superiore. Tono emozionale.','Tre voci. Due chitarre. Un''unica emozione. Ancreus live a COINCIDENZE. Ore 11:00 e 16:00 · Sala Superiore. Alberto Calandri · Diego Cavallero · Giorgia Bruno. #COINCIDENZE2026 #LiveMusic','Post o Reel (snippet audio)','da_fare','["Ancreus"]','Collab con @ancreus. Ideale un Reel con snippet musicale 15-30sec.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p07','2026-04-13',2,'artisti','🍷','Spotlight — Cucina e Vino','La cucina di Marco e Alice + degustazione vini di Silvio Altare. Contenuto cibo/vino performa bene (28 like nell''Ed.0).','Un tavolo apparecchiato tutto il giorno. La cucina di Marco e Alice. I vini selezionati da Silvio Altare. Ristorante, Giardino e Portico · 10:00-20:00. #COINCIDENZE2026 #VinoECucina #MarsamLocanda','Carosello o Reel (food)','da_fare','["Marco Marsam","Silvio Altare","Serena Colombo"]','Il food content ha il miglior engagement storico. Collab @marsamlocanda. Reel food consigliato.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p08','2026-04-14',2,'artisti','📖','Spotlight — Michele Marziani','Due presentazioni libri. Lo Sciamano delle Alpi + secondo libro. Conduce Samantha Viva.','Parole che aprono mondi. Michele Marziani presenta due libri a COINCIDENZE. 11:30 Lo Sciamano delle Alpi · 15:00 secondo libro. Orto Romano. Conduce @sammiworld. #COINCIDENZE2026 #Libri #MicheleMarziani','Post quadrato o carosello','da_fare','["Michele Marziani"]','Collab @micmarziani e @sammiworld. Post di Samantha amplifica enormemente (295 like storico).');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p09','2026-04-16',2,'artisti','🎭','Spotlight — Teatro e Esperienze','Delfina Testa (tarocchi), Petra Lindblom (sciamana), Pietro Fantone (AI video). Le esperienze immersive.','Tarocchi nel giardino. Sciamana dalla Svezia. AI e video. Tre esperienze da vivere. Delfina Testa · Petra Lindblom · Pietro Fantone. #COINCIDENZE2026 #Teatro #VideoAI','Carosello (4 slide)','da_fare','["Delfina Testa","Petra Lindblom","Pietro Fantone"]','3 novita'' assolute dell''Ed.1. Tono misterioso/intrigante.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p10','2026-04-17',2,'artisti','🎬','Spotlight — Cristina Saimandi e A Passo Lento','Corto dal Monviso. Scultrice e scalatrice. Proiezione 17:00 Sala Superiore.','Dal cuore delle campagne saviglianesi alla cima del Monviso. Cristina Saimandi porta a COINCIDENZE il suo cortometraggio A Passo Lento. Proiezione ore 17:00 · Sala Superiore. #COINCIDENZE2026 #APassoLento','Post o Reel (trailer)','da_fare','["Cristina Saimandi"]','Collab @cristinasaimandiartist. Se c''e'' un trailer del corto, usare come Reel.');
INSERT INTO editorial_posts (id, data, fase, tag, emoji, titolo, descrizione, caption_suggerita, formato, stato, artisti_coinvolti, note) VALUES
('p11','2026-04-19',3,'countdown','🗓','Programma completo','Carosello con timeline ora per ora. Una slide per fascia oraria.','Una giornata intera da vivere. 10:00 Mostre aperte · 11:00 Ancreus Live · 11:30 Michele Marziani · 12:00 Tarocchi · 13:00 AI e Video · 14:00 Petra Lindblom · 15:00 Marziani 2 · 16:00 Ancreus Live 2 · 17:00 A Passo Lento · 18:00 Pasta Comune. 25 aprile · Marsam Locanda. #COINCIDENZE2026','Carosello (8-10 slide)','da_fare','[]','Grafica pulita. Una slide per fascia oraria con icona categoria.');
